UPDATE gameRules SET details = '{"type":"table","link":{"url":"http://mahjong-europe.org/portal/images/docs/Riichi-rules-2025-EN.pdf","label":"Офіційні правила EMA 2025 (PDF)"},"table":{"headers":["Правило","Значення"],"rows":[["Кількість гравців","4"],["Стартові очки","0 (EMA)"],["Чомбо","20,000 очок після ума"],["Очки продовження","3x100"],["Червоні п''ятірки","❌"],["Пріоритет","рон → перший"],["Аґарі яме","❌"],["Банкрутство","❌"],["Округлення до манґану","✅"],["Підрахований якуман","❌"],["Накладання якуманів","❌"],["Ріічі без наступного ходу","✅"],["Подвійне ріічі","2️⃣"],["Наґаші манґан","❌"],["Подвійний якуман","❌"],["Подвійний вітер","2 фу"],["Ума","15 / 5 / -5 / -15"]],"rowTooltips":[null,null,{"label":"Чомбо","content":"Штраф 20,000 очок після розрахунку ума за порушення правил гри."},{"label":"Хонба","content":"Стандартна"},null,{"label":"Пріоритет","content":"Рон завжди має пріоритет. Далі той, хто заколив перший."},{"label":"Аґарі яме","content":"Гра продовжується до кінця ханчану (раунду), навіть якщо хтось з гравців досяг цільового рахунку."},{"label":"Банкрутство","content":"≤ 0: Гра закінчується, коли рахунок гравця досягає нуля (або менше).\n\n< 0: Гра закінчується, коли рахунок гравця стає від''ємним. Гра продовжується, коли гравець має рівно нуль очок."},{"label":"Округлення до манґану","content":"4 хан 30 фу коштує як манґан"},null,null,null,null,null,null,null,{"label":"Ума 15/5","content":"Фіксована ума:\n  15 / 5 / -5 / -15"}]}}' WHERE id = 4;
UPDATE gameRules SET details = '{"type":"table","link":{"url":"https://riichi.wiki/Mahjong_Soul","label":"Mahjong Soul на Riichi Wiki"},"table":{"headers":["Правило","Значення"],"rows":[["Кількість гравців","4"],["Стартові очки","25,000"],["Ума","15 / 5 / -5 / -15"],["Тай-брейк ума","За вітром"],["Червоні п''ятірки","3 (по одній на масть)"],["Відкритий таняо (куітан)","✅"],["Атодзуке","✅"],["Куікае (підміна)","❌"],["Подвійний вітер","4 фу"],["Подвійний / потрійний рон","✅"],["Хонба","3x100"],["Ренчан","Поки дилер виграє"],["Наґаші манґан","✅"],["Продовження матчу (енчьосен)","✅"],["Банкрутство (тобі)","< 0"],["Кандора — закритий кан","Відразу"],["Кандора — відкритий кан","Після"],["Закритий кан під час ріічі","✅ (з обмеженнями)"],["Залишок ріічі депозитів","1-му місцю"],["Абортивні нічиї","Суфу, Сукан, Кюшу, Суча"],["Санчахо (рон трьох)","❌"],["Пінфу","Цумо 20 фу, Рон 30 фу"],["Чітойцу","25 фу"],["Іппацу + Ріншян","❌"],["Кокуші — відкритий кан","✅"],["Чюрен — відкритий кан","❌"],["Секінін бараі (пао)","Дайсанґен, Дайсуші"],["Композитний якуман","✅"]],"rowTooltips":[null,null,{"label":"Ума 15/5","content":"Фіксована ума:\n  1-й: +15\n  2-й: +5\n  3-й: -5\n  4-й: -15"},{"label":"Тай-брейк за вітром","content":"При однаковому рахунку вищу позицію отримує гравець з меншим номером вітру (схід → південь → захід → північ)"},null,{"label":"Куітан","content":"Дозволено збирати таняо (всі прості) у відкритій руці"},{"label":"Атодзуке","content":"Дозволено виграти, навіть якщо яку з''являється лише завдяки виграшному тайлу"},{"label":"Куікае","content":"Заборонено скидати тайл, який щойно використовувався для чі/пон"},null,{"label":"Подвійний рон","content":"При кількох ронах — депозити ріічі отримує гравець, найближчий за чергою до того, хто скинув (атамахане)"},null,{"label":"Ренчан","content":"При подвійному роні: дилерство зберігається, якщо дилер виграв, інакше переходить.\n\nПри наґаші манґан: зберігається, якщо дилер у темпай, інакше переходить."},null,{"label":"Енчьосен","content":"Якщо після останнього раунду жоден гравець не досяг 30,000 очок, гра продовжується додатковими раундами"},{"label":"Банкрутство","content":"Гра закінчується, коли рахунок гравця стає від''ємним (< 0).\n\nГра продовжується, коли гравець має рівно нуль очок."},{"label":"Кандора — закритий кан","content":"Новий індикатор дори перевертається відразу після оголошення закритого кану"},{"label":"Кандора — відкритий кан","content":"Новий індикатор дори перевертається після завершення ходу (скиду тайлу)"},{"label":"Закритий кан під час ріічі","content":"Дозволено за двох умов:\n1. Тайл для кану витягнуто безпосередньо\n2. Очікування не змінюється після кану"},null,{"label":"Абортивні нічиї","content":"Суфу ренда — 4 однакові вітри на першому скиді\nСукан наґаре — 4 кани різними гравцями\nКюшу кюхай — 9 різних благородних на першому ході\nСуча ріічі — усі 4 гравці оголосили ріічі"},{"label":"Санчахо","content":"Потрійний рон (3 гравці оголошують рон одночасно) не призводить до абортивної нічиї. Усі три рони зараховуються."},{"label":"Пінфу","content":"Цумо: рахується як 20 фу (без 10 фу за цумо)\nРон: рахується як 30 фу"},{"label":"Чітойцу","content":"Завжди 25 фу, незалежно від складу пар"},{"label":"Іппацу + Ріншян","content":"Іппацу та Хайтей не можуть комбінуватися з Ріншян кайхо"},{"label":"Кокуші — закритий кан","content":"Дозволено перехопити (рон) чужий закритий кан, якщо є готова рука на кокуші мусо"},{"label":"Чюрен — закритий кан","content":"Не дозволено перехоплювати чужий закритий кан для чюрен пото"},{"label":"Секінін бараі (пао)","content":"Відповідальність за виплату:\n— Дайсанґен: гравець, що віддав тайл для 3-го пону драконів\n— Дайсуші: гравець, що віддав тайл для 4-го понгу вітрів\n\nПри композитному якумані — відповідальність розділяється окремо за кожен якуман"},{"label":"Композитний якуман","content":"Дозволено комбінувати кілька якуманів в одній руці.\n\nОсобливість Тенхо: дилер починає з 14 тайлів, тому будь-який тайл може вважатися виграшним. Це означає, що Тенхо завжди комбінується з подвійними варіантами якуманів (Суанко танкі, Кокуші 13-wait, Чюрен 9-wait) = потрійний якуман."}]}}' WHERE id = 5;
UPDATE gameRules SET details = '{"type":"table","link":{"url":"https://riichi.wiki/Mahjong_Soul#3P-Mahjong","label":"Mahjong Soul Sanma на Riichi Wiki"},"table":{"headers":["Правило","Значення"],"rows":[["Кількість гравців","3"],["Стартові очки","35,000"],["Цільові очки","40,000"],["Ума","15 / 0 / -15"],["Тай-брейк ума","За вітром"],["Червоні п''ятірки","2 (🀝 та 🀤)"],["Видалені тайли","2–8 манзу"],["Хонба","3x200"],["Штраф за нотен","2,000"],["Тайлів рінсян","8"],["Чі","❌"],["Північ (кіта/пей)","Нукідора"],["Рінсян від кіта","✅"],["Рон на кіта","✅ (без чанкан)"],["Кіта після пон","❌"],["Кіта скасовує","Іппацу, Чіхо, Кюшу, Дабурі"],["Кіта та фурітен","Не впливає"],["Північ як яку","❌ (отакадзе)"],["Саншоку","❌ (немає манзу)"],["Дора після 1 манзу","9 манзу"],["Абортивні нічиї","Сукан, Кюшу"],["Суфу / Суча","❌ (3 гравці)"],["Підрахунок очок","Цумо-лосс (ранковані)"]],"rowTooltips":[null,null,{"label":"Цільові очки","content":"Якщо після останнього раунду жоден гравець не досяг 40,000 очок, гра продовжується додатковими раундами (енчьосен)"},{"label":"Ума 15/0/-15","content":"Фіксована ума:\n  1-й: +15\n  2-й: ±0\n  3-й: -15"},{"label":"Тай-брейк за вітром","content":"При однаковому рахунку вищу позицію отримує гравець з меншим номером вітру (схід → південь → захід)"},null,{"label":"Видалені тайли","content":"Тайли від 2 до 8 манзу не використовуються.\n\nЧерез це саншоку (змішана потрійна послідовність) неможлива.\n\nКоли індикатор дори — 1 манзу, дорою є 9 манзу."},{"label":"Хонба","content":"Кожна паличка хонба додає 200 очок (замість 100 у 4-гравцевому маджонзі)"},null,null,{"label":"Чі заборонено","content":"У санма не можна оголошувати чі. Дозволені лише пон і кан."},{"label":"Нукідора (кіта)","content":"Північ можна викласти як замінну дору (нукідора/пей). Це дає +1 хан, аналогічно червоній п''ятірці.\n\nВиграш рукою з рінсян тайлу від заміни Півночі зараховується як Рінсян кайхо."},{"label":"Ріншян від кіта","content":"Коли гравець замінює Північ і тягне тайл з ріншян — виграш цим тайлом рахується як Рінсян кайхо (яку)"},{"label":"Рон на кіта","content":"Можна оголосити рон, коли інший гравець замінює Північ, навіть без якумана.\n\nАле яку Чанкан НЕ зараховується — потрібна інша яку для виграшу."},{"label":"Кіта після пон","content":"Не можна замінювати Північ відразу після оголошення пон"},{"label":"Кіта скасовує","content":"Заміна Півночі вважається дією виклику, тому скасовує:\n— Іппацу\n— Чіхо (благословення землі)\n— Кюшу кюхай (9 термінальних)\n— Дабуру ріічі (подвійне ріічі)"},{"label":"Кіта та фурітен","content":"Якщо гравець очікує на Північ, заміна Півночі іншим гравцем не створює фурітен"},{"label":"Північ як яку","content":"Північ у руці вважається отакадзе (гостьовий вітер). Триплет Півночі НЕ дає 1 хан як якухай."},null,null,null,null,{"label":"Цумо-лосс","content":"За замовчуванням у рангових матчах. Переможець втрачає дохід від місця Півночі при цумо.\n\nТаблиця очок ідентична 4-гравцевому маджонгу.\n\nАльтернатива (для дружніх матчів): Розподіл Півночі — дохід від місця Півночі ділиться порівну між іншими гравцями (округлення вгору до сотень).\n\nПриклад (Розподіл): Не-дилер, 40 фу 3 хан:\n— 4P базис: дилер 2600, не-дилер 1300\n— Північ платить 1300, половина = 650 → 700\n— Дилер: 2600 + 700 = 3300\n— Не-дилер: 1300 + 700 = 2000"}]}}' WHERE id = 6;
UPDATE gameRules SET details = '{"type":"table","table":{"headers":["Правило","Значення"],"rows":[["Кількість гравців","4"],["Стартові очки","25,000"],["Ума","15 / 5 / -5 / -15"],["Тай-брейк ума","Порівну"],["Червоні п''ятірки","3 (по одній на масть)"],["Відкритий таняо (куітан)","✅"],["Атодзуке","✅"],["Куікае (підміна)","❌"],["Подвійний вітер","2 фу"],["Подвійний / потрійний рон","✅"],["Хонба","3x100"],["Ренчан","Поки дилер виграє"],["Наґаші манґан","✅"],["Продовження матчу (енчьосен)","✅"],["Банкрутство (тобі)","< 0"],["Кандора — закритий кан","Відразу"],["Кандора — відкритий кан","Відразу"],["Закритий кан під час ріічі","✅ (з обмеженнями)"],["Залишок ріічі депозитів","1-му місцю"],["Абортивні нічиї","❌"],["Санчахо (рон трьох)","❌"],["Пінфу","Цумо 20 фу, Рон 30 фу"],["Чітойцу","25 фу"],["Іппацу + Ріншян","❌"],["Кокуші — відкритий кан","✅"],["Чюрен — відкритий кан","❌"],["Секінін бараі (пао)","Дайсанґен, Дайсуші"],["Композитний якуман","✅"],["Ренхо","Якуман"],["Кіріаґе манґан","✅"],["Пріорітет","Рон -> кан/пон/чі хто перший."]],"rowTooltips":[null,null,{"label":"Ума 15/5","content":"Фіксована ума:\n  1-й: +15\n  2-й: +5\n  3-й: -5\n  4-й: -15"},{"label":"Тай-брейк за вітром","content":"При однаковому рахунку вищу позицію отримує гравець з меншим номером вітру (схід → південь → захід → північ)"},null,{"label":"Куітан","content":"Дозволено збирати таняо (всі прості) у відкритій руці"},{"label":"Атодзуке","content":"Дозволено виграти, навіть якщо яку з''являється лише завдяки виграшному тайлу"},{"label":"Куікае","content":"Заборонено скидати тайл, який щойно використовувався для чі/пон"},null,{"label":"Подвійний рон","content":"При кількох ронах — депозити ріічі отримує гравець, найближчий за чергою до того, хто скинув (атамахане)"},null,{"label":"Ренчан","content":"При подвійному роні: дилерство зберігається, якщо дилер виграв, інакше переходить.\n\nПри наґаші манґан: зберігається, якщо дилер у темпай, інакше переходить."},null,{"label":"Енчьосен","content":"Якщо після останнього раунду жоден гравець не досяг 30,000 очок, гра продовжується додатковими раундами"},{"label":"Банкрутство","content":"Гра закінчується, коли рахунок гравця стає від''ємним (< 0).\n\nГра продовжується, коли гравець має рівно нуль очок."},{"label":"Кандора — закритий кан","content":"Новий індикатор дори перевертається відразу після оголошення закритого кану"},{"label":"Кандора — відкритий кан","content":"Новий індикатор дори перевертається після завершення ходу (скиду тайлу)"},{"label":"Закритий кан під час ріічі","content":"Дозволено за двох умов:\n1. Тайл для кану витягнуто безпосередньо\n2. Очікування не змінюється після кану"},null,{"label":"Абортивні нічиї","content":"Суфу ренда — 4 однакові вітри на першому скиді\nСукан наґаре — 4 кани різними гравцями\nКюшу кюхай — 9 різних благородних на першому ході\nСуча ріічі — усі 4 гравці оголосили ріічі"},{"label":"Санчахо","content":"Потрійний рон (3 гравці оголошують рон одночасно) не призводить до абортивної нічиї. Усі три рони зараховуються."},{"label":"Пінфу","content":"Цумо: рахується як 20 фу (без 10 фу за цумо)\nРон: рахується як 30 фу"},{"label":"Чітойцу","content":"Завжди 25 фу, незалежно від складу пар"},{"label":"Іппацу + Ріншян","content":"Іппацу та Хайтей не можуть комбінуватися з Ріншян кайхо"},{"label":"Кокуші — закритий кан","content":"Дозволено перехопити (рон) чужий закритий кан, якщо є готова рука на кокуші мусо"},{"label":"Чюрен — закритий кан","content":"Не дозволено перехоплювати чужий закритий кан для чюрен пото"},{"label":"Секінін бараі (пао)","content":"Відповідальність за виплату:\n— Дайсанґен: гравець, що віддав тайл для 3-го пону драконів\n— Дайсуші: гравець, що віддав тайл для 4-го понгу вітрів\n\nПри композитному якумані — відповідальність розділяється окремо за кожен якуман"},{"label":"Композитний якуман","content":"Дозволено комбінувати кілька якуманів в одній руці.\n\nОсобливість Тенхо: дилер починає з 14 тайлів, тому будь-який тайл може вважатися виграшним. Це означає, що Тенхо завжди комбінується з подвійними варіантами якуманів (Суанко танкі, Кокуші 13-wait, Чюрен 9-wait) = потрійний якуман."},{"label":"Ренхо","content":"Рон на першому колі до свого ходу"},{"label":"Кіріаґе манґан","content":"4 Хан 30 фу завжди манґан"},null]}}' WHERE id = 7;
